solution.code:
#include <stdio.h>
#include <math.h>

int main() {
    int n = 1010, decimal = 0, i = 0;
    while (n > 0) {
        int rem = n % 10;
        decimal += rem * pow(2, i);
        n /= 10;
        i++;
    }
    printf("%d\n", decimal);
    return 0;
}
